#include<iostream>
#include<stdio.h>
#include<stdlib.h>

using namespace std;
const int N=110,M=1e7+10;
int n,weight[N];
bool ans[M],visited[N][M];
void dfs(int i,int val) {
	if(i>n) {
		if(val>0)
			ans[val]=true;
		return ;
	}
	if(visited[i][val]) {
		return ;
	}

	dfs(i+1,val);
	dfs(i+1,val+weight[i]);
	dfs(i+1,abs(val-weight[i]));

	visited[i][val]=true;
}
int main() {
	cin>>n;
	for(int i=1; i<=n; i++) {
		cin>>weight[i];
	}
	dfs(1,0);
	int cnt=0;
	for(int i=1; i<=M; i++)if(ans[i])cnt++;
	cout<<cnt;
	return 0;
}
